INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("やばいですね☆なの！", 3, 1, "プリンセスなプリンなの\nお店にあったいろんな食べもの\nを入れられるだけ入れてみたの\nどんな味なのか楽しみなの", 1, 100, "ペコリーヌのプリン", "おいしすぎて食べ始めたら\n止まらない最高のプリンなの\n今のミヤコを止められるヤツは\n誰もいないの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("主さま、なの！", 3, 2, "いつもオマエのそばに寄りそう\nヤツのぷりんなの。ミヤコの\nワガママもやさしく受け入れて\nくれそうなの", 1, 101, "コッコロのプリン", "なんだかすごくやさしい気持ち\nになる味なの…\nおはようからおやすみまで\nずっと一緒な味なの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ぶっ殺すぞ！なの！\n…デレデレはどこなの？", 3, 3, "ツンツンデレデレなヤツの\nプリンなの。砂糖とスパイスを\n混ぜてみたの。どんな味になる\nか楽しみなの", 0, 102, "キャルのプリン", "いろんな味が一度で楽しめる\nプリンなの。ツンデレはプリン\nにするとおいしいの。ミヤコも\nツンデレを目指してみるの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("おにーたん♪なの！", 3, 4, "オマエと同じで、一度赤ちゃん\nみたいになったヤツのプリン\nなの。ヒンヤリ、プリンアイス\nにしてみたの", 1, 103, "シェフィのプリン", "あったかいところで食べる\nプリンアイスは最高なの～♪\n安心しすぎて昔の記憶のない\nミヤコも心が子どもになるの～", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ハーハッハッハ！\n世界征服なのじゃなのー！", 3, 5, "イリヤを見てたら思いついた\nトマトジュースが隠し味の\nプリンなの。栄養満点なの", 1, 104, "イリヤのプリン", "トマトで栄養補給も完璧なの\nどんどん力がみなぎってきて\n復活も夢じゃないの\nミヤコが復活したら…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("お兄ちゃんのエッチ！　なの！", 3, 6, "アカリのプリンなの。ヨリと\n同じくらいかわいく作って\nやったの。正直ミヤコは\nおいしければなんでもいいの", 1, 105, "アカリのプリン", "見た目がかわいくてもミヤコは\n味にも厳しいの。あむっ…\nこ、これは…！なんだかすごく\n変な気分になってきたの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("えっと…その…あんたのこと…\nだ、大っ嫌いなのーー！", 3, 7, "かわいくつくらないとアカリが\n怒りそうだからヨリのプリンは\nかわいく作ったの。自信作なの", 1, 106, "ヨリのプリン", "んむぅ…これはなかなか感想が\n難しいプリンなの…率直に言い\nたいような…心のうちに秘めて\nおきたいような…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("お父さん…\nいいかげんにしてなの！\nん？プリンの未来は…\n見えなかったの…", 3, 8, "シノブはいつもミヤコに\nやさしくしてくれるから\n丁寧に作ったの。ドクロ親父は\nいらないから作ってないの", 0, 107, "シノブのプリン", "このプリンを食べるとシノブが\nミヤコの中にいるみたいなの！\nシノブの力があれば未来の\nプリンを見放題なの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("インフェルノシールド！なの！", 3, 9, "黒い鎧を脱がないヤツのプリン\nなの。固めのプリンを目指したら\nカチカチになりすぎたの", 1, 108, "ジュンのプリン", "固すぎてかじれないから丸吞み\nにしたの。なんだか体が硬く\nなった気がするの。みんなを\n守れる気がするの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("あなたといると調子が狂うな\n…なの\n翻弄してたのはオマエなの？", 3, 10, "オマエをいっつもからかってる\nヤツのプリンなの\nちょっぴり変わったスパイスで\nからかいを表現したの", 1, 109, "トモのプリン", "口の中でスパイスがプチプチ\nはじけて新食感なの！\nプチプチがミヤコを\n翻弄するの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("タイガーヒーローボンバー！\nなの！", 3, 11, "王宮騎士団にいるちっこいヤツ\nなの。ちっこいけどやるヤツ\nらしいから、濃いめの味付けに\nしてみたの", 1, 110, "マツリのプリン", "ん～見かけによらず濃厚な\nパンチのある味わいが\n口いっぱいに広がるの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ま、いいんじゃん？\nしらんけどなの", 3, 13, "なんかすごくクールなプリンなの\nなんかテンションも少し\n低そうなの。これ\n食べちゃっても大丈夫なの？", 1, 111, "クロエのプリン", "クールな見た目なのにとっても\n優しい味なの！なんだか\n懐かしさを感じるの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ぷりーん★なの！", 3, 14, "きれいにデコれたの！\nカラフルでおいしそうなの\nこれは期待できそうなの", 1, 112, "チエルのプリン", "なんか変わった食感なの…\nちゃる…ちょる…ちぇる？\nちぇるってしてるの\nでもちぇるってなんなの？", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("端的に換言すれば\n青春の味なの？", 3, 15, "見た目は完ぺきなの！\nこれをつくったやつは\nきっと天才なの！\n早く食べたいの！", 1, 113, "ユニのプリン", "味はなんか妙に\n甘酸っぱいの…\n食べたことない味なの\nこの味ってもしかして…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("幼なじみはあんた…なの？", 3, 16, "オマエから聞いた懐かしい\n味ってヤツを全部入れてみたの\nオマエ記憶がないのに懐かしい\nってどういうことなの？", 1, 114, "サレンのプリン", "ミヤコも幽霊になる前の記憶\nがないのに、なんだか懐かしい\n気持ちになってくるの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ひゃああんなの～！", 3, 17, "たまたま会ったメイドに教えて\nもらった作り方なの。メイドは\nプリンも作れるはずなの。\nなのにこの不安は何なの…？", 1, 115, "スズメのプリン", "おかしいの。このプリンを\n食べてから、３回も転んだの\nミヤコは幽霊だから転んだり\nしないの。なんでなの…？", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("サルキデバレヤ！なの！", 3, 18, "怖がりな子どもが教えてくれた\n小さくてかわいいプリンなの　\n触ってないのにぷるぷる震える\n驚きのやわらかさなの", 0, 116, "クルミのプリン", "甘さのなかに少しのしょっぱさ\nクセになる味なの\nこのプリンはがんばればきっと\nいろんな美味しいになれるの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("プリンフルスイングなの～！", 3, 19, "くまのぬいぐるみを見ていたら\nひらめいたの。小さいけど\nしっかりした甘さの元気に\nなれるプリンなの！", 1, 117, "アヤネのプリン", "このプリン、食べるとなんだか\nお姉ちゃんになった気分に\nなるの。ピンチのプリンは\nミヤコが守ってやるの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("みらくるみやりん\nくるりんぱ～☆なの！", 3, 20, "マホマホ王国って国にいる\nお姫様のプリンなの\n魔物も虜にしちゃう\nすてきなプリンなの", 1, 118, "マホのプリン", "メルヘンパワーがあふれてきて\nいまならミヤコにも魔法が\n使える気がするの！\nほな、いきまひょ～なの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ウルフェンバイトなの！", 3, 21, "カッコいいプリンを目指して\nワイルドなものをガンガン\n入れてみたの。きっと熱い\nプリンができるはずなの", 1, 119, "マコトのプリン", "うおーん！ミヤコなんだか\n強くなった気がするの！\n困ったことがあればミヤコが\nまとめて面倒見てやるの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("なんくるないさ～！なの！", 3, 22, "どっかの国でよくとれる\nゴーヤーに似てるやつを\nいれてみたの！ちょっと\n苦いらしいけど…", 1, 120, "カオリのプリン", "一口食べたら元気が\nあふれて止まらないの！\n気分がいいから、一曲\n踊りでも披露してやるの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ふふん。簡単な推理なの", 3, 23, "勘の鋭いやつが好きな食べ物を\nたくさん入れてみたの\n難しいこと考えるのにぴったり\nらしいけど、なんでなの？", 1, 121, "カスミのプリン", "むむむ…なるほどなの\n上質な糖分をふんだんに\n使うことで、脳をより活性化\nできるからなの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("エリザベス～！なの～！", 3, 24, "搾りたての牛乳を\nたっぷり使ったプリンなの～\nマヒルに手伝ってもらって\nミヤコ直々に搾ってきたの！", 1, 122, "マヒルのプリン", "ミルクがとっても濃厚で\nほっぺたが落ちちゃうの～♪\nこのプリンからは牧場の…\n自然の息吹を感じるの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("私の好きな本…読んで\nもらえたらうれしいです…\nなの", 3, 25, "マヒルからやさしいヤツだって\n聞いたの。やさしさを表現\nするために奥ゆかしい甘さに\n仕上げてみたの", 1, 123, "シオリのプリン", "ほのかな甘さでありながら\nしっかりとした主張も\n感じさせる\n味わい深いプリンなの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("もふもふにしてあげるなの！", 3, 26, "牧場にいるヤツらしいの\n牛とは違うらしいの\nもふもふ気持ちいいらしいから\n食感にこだわって作ったの", 1, 124, "リマのプリン", "こ、これは…！口の中に入れた\n瞬間にふんわり溶けて\nなくなっちゃうの！\nその食感がやみつきなの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("めんどくさいな～なの…", 3, 27, "いっつも寝てるやつらしいの\nぐっすり眠れる薬草をたくさん\n入れてみたの。プリンとして\nおいしくなるかはわからないの", 0, 125, "リンのプリン", "んむぅ…評価が難しい味なの…\nおいしいのはおいしいの…\nん～考えてたら…\n眠くなってきたの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("プリンの権能を解放するの～！", 3, 28, "クレープ屋の真っ赤な人に\n教わったプリンなの\n作り方を丁寧に教えてくれて\nとっても優しい人だったの！", 1, 126, "ラビリスタのプリン", "プ…プリンなのにクレープの味\nがするの。味もすごく普通なの\nでも…なんだかプリンの新しい\n扉を開けそうな気がするの…！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("お姉ちゃんパワー全開！なの！", 3, 29, "お店に落ちてた謎のレシピの\nプリンなの。レシピの表紙には\n『お姉ちゃんの愛情たっぷり』\nって書いてあったの", 0, 127, "シズルのプリン", "とろける食感が絶品なの～♪\n食べるとなんだか幸せな\n気持ちになれるの…これが\n愛情ってやつなの？", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("お兄ちゃん、プリンをよこすの！", 3, 30, "リノから作り方を教わったの！\nさすがクレープ屋で働いてる\nだけあって美味しそうなの！", 1, 128, "リノのプリン", "これで妹力？があがるらしいの。\n妹になればお兄ちゃんに\nプリンをたかり放題なの！\n最高なの～！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("困った時はお互いさまさま！\nなの！", 3, 31, "プリンのレシピで悩んでたら\n通りすがりのおねーさんが\n一緒に考えてくれたプリンなの\nいいヤツもたまにはいるの～♪", 1, 129, "ヒヨリのプリン", "食べたら元気が湧いてくるの\nだからプリンのレシピのお礼に\nミヤコも人助けを手伝って\nやったの。ミヤコはえらいの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("フラワリングヒールなの～♪", 3, 32, "ミヤコががんばって作った\nこだわりのプリンなの～\nプリンは癒しなの。だから優しい\n気持ちで丁寧に作ったの", 1, 130, "ユイのプリン", "はっ…思わずお花畑が見えたの\n身も心も包まれるような\nとっても優しい味がするの\nこれは…まさに癒しなの～♪", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("スラッシュテンペスト！なの。", 3, 33, "究極のプリンを作るため\nミヤコは厳しい修行をしたの…\nその結果あって完成した\nクールで完璧なプリンなの！", 1, 131, "レイのプリン", "確かに完璧なプリンなの\nでも究極のプリンと呼ぶには\nまだまだ修行が必要なの…\nプリン作りは奥が深いの…！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("おーほっほほほ！なの！", 3, 34, "豪華で高級な\nお嬢様プリンなの\n中には宝石みたいな\n大きいイチゴを入れるの！", 1, 132, "アキノのプリン", "味にも素材にもこだわりが\nあるの。一流は妥協しないの\nもっと豪華に、もっとおいしく\nできるはず…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("プリしゅわ最高～！なの！", 3, 35, "外はしっかり、中はふわとろの\nプリンにするの\n泡みたいなしゅわしゅわの\n生クリームも入れるの♪", 1, 133, "ユカリのプリン", "プリンは飲み物とも言うの\nぐいっていってみるの\n…ふわしゅわでとろけるの～！\n体に染みわたるの～", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("にゃにゃにゃ！なの！", 3, 36, "餡子を入れて\nオーブンでこんがり焼くの\nたい…焼きプリンなの\n斬新なの！", 1, 134, "タマキのプリン", "このプリンは焼きたてのうちに\n食べるのが一番なの…！\n熱いけどおいしくて\nうずうずしてきたの…！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("効率全開！なの！", 3, 37, "栄養バランスを考えて\n木の実をたくさん入れるの\nあれこれ忙しいときでも\n頼りになるプリンなの！", 0, 135, "ミフユのプリン", "プリンはいつでも手軽に\n食べられるのも魅力なの\nこれは食べ応えもあるから一つ\n食べればいっぱい動けるの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("あらあら～なの～♪", 3, 38, "エルフの森で子どもにもらった\n薬草を使って作ったの\nこんな優しい味のプリンは\n初めてなの…", 1, 136, "ミサトのプリン", "このプリンを食べてから\nいい子になった気がするの\n大好きなプリンを泣いてる子に\nあげたの。いい気分なの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("スヤスヤ～…なの…", 3, 39, "お昼寝でみた夢の中に\nでてきた不思議なプリンを\n作ってみたの。見てたらまた\n眠くなってきたの…", 1, 137, "ハツネのプリン", "あまいプリンが口の中で\nぽんぽん弾ける未知の味なの！\n今なら不思議な力で世界も\n救えそうなの！でも眠くなるの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ぼっちは卒業なの～！", 3, 40, "お店のはしっこに一つだけ\n残ったおもちゃを見て思い\nついたの。他のプリンと一緒に\n置いておくと震えだすの", 1, 138, "アオイのプリン", "知らないうちにはしっこに\n隠れちゃってたの。食べたら\nミヤコ、シノブたちに会いに\nいきたくなってきたの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("リズムあげるのー！", 3, 41, "トップオブアイドルの\nプリンなの。キラキラした\nものを入れて、あつ～い\nオーブンで焼いてみたの", 1, 139, "ノゾミのプリン", "口の中に華やかな甘さが\n広がる…これがアイドルなの？\n急に歌って踊りたく\nなってきたの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("風の加護を！なの！", 3, 42, "ミヤコにプリンをくれるすごく\nいいヤツのプリンなの\n精霊に呼びかけながら\n一生懸命かき混ぜたの", 1, 140, "チカのプリン", "プリンの生地がとっても\nなめらかで最高の舌触りなの！\n精霊、ミヤコのプリンのために…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("騎士さんのために\nしたんじゃありません！なの！", 3, 43, "歌って踊って衣装も作れるヤツ\nのプリンなの。このプリンは\nきれいに包装するの。プリンを\n最高の形で着飾らせるの", 1, 141, "ツムギのプリン", "包装は食べるまでの手間が\n増えてめんどくさいの。でも\nそのめんどくささもプリンの\n味を引き立てるの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("宴の始まりなの！", 3, 12, "プリンをくれないならどうでも\nいいヤツなの。でも横で\nいろいろ言ってきたから\nがんばって作ったの", 0, 142, "クリスティーナのプリン", "んむっ！？\nく、口のなかでプリンの\nおいしさが大暴れなの！\n止まらないの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("一刀両断、覚悟しな！なの！", 3, 44, "大人な甘さ控えめのプリンを\n作るの。試しにお魚を入れて\nみるの。プリンの可能性は\n無限大なの！", 1, 143, "ルカのプリン", "大人の味なの。今やミヤコは\nみんなの頼れる姐御なの！\n悪さするやつはミヤコが\n許さないの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("きゅぴーん！キタコレ！なの！", 3, 45, "サイカワサイツヨな\n魔法のプリンなの\n中身をカラフルにするの～\n甘いプリンは頭が冴えるの！", 1, 144, "ナナカのプリン", "一口食べる度に味が変わって\n魔法みたいなの！\nもしかして全部食べたら\nミヤコも魔法少女になれるの？", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("人呼んで、疾風のミヤコなの！", 3, 46, "小難しい言葉をささやきながら\n作ったら魔力あふれるプリンが\n爆誕したの！でも、不思議と\nイタイタしいのはなぜなの～？", 1, 145, "アンナのプリン", "一口食べたら謎の組織に\n狙われたり、前世の記憶が蘇る\n気がするの～設定盛りすぎなの\nミヤコは、ミヤコは…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("クスクス…クスクスクス…なの", 3, 47, "甘酸っぱい赤い木の実を\n切り刻んで入れるの\n甘くてちょっぴり刺激的な\nヤンデレのプリンなの", 1, 146, "エリコのプリン", "なんか普通のプリンよりも\nいい匂いがするの～…\nプリンのことがもっともっと\n好きになっちゃうの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("どんなプリンも\nミヤコの隻眼からは\n逃れられないの～！", 3, 48, "健康に気を遣うミヤコは\nプリンにお薬を入れてみたの～\nでもなんだか毒々しいから\n彩りにバラを添えてみたの～", 1, 147, "ミツキのプリン", "鼻に抜ける薬のにおいがアレ\nだけど大人っぽくて頭が\nよくなった気がするの。無性に\n実験したくてしかたないの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("私は子どもではない！なの！", 3, 49, "小さいけどしっかりした\n軍人のプリンなの\nちょっと固めにして\n砂糖はいっぱい入れるの", 1, 148, "モニカのプリン", "ん～王道なプリンは\n甘くて安定したおいしさなの～\n思わず笑顔になっちゃうの\nにこにこなの～♪…はっ！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ショーグン！　ミヤコと一緒に\n天下統一するデースなの！", 3, 50, "オーエド町で手に入れた素材と\nトーゴクに伝わる術をかけて\nプリンを作るの。シュババ！\n忍法隠し味の術なの！", 1, 149, "ニノンのプリン", "このプリンを食べてから\n誰かにお仕えしなきゃ\nいけない気がするデースなの\nそれはショ、ショー…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("…ぐふふ、じゅるり～なの", 3, 51, "オマエが持ってきた手錠を\nヒントに作ったプリンなの\nプリンが動けないように\nカチカチに固めたの", 0, 150, "クウカのプリン", "カチカチに固めたせいで食感が\nプリンのようで\nプリンじゃないの…でもこの\nもどかしさが癖になるの…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("あぁ、ミヤコはなんて美しいの～", 3, 52, "とっても美しいプリンなの\n美しいものを手当たり次第\n入れたらすごいことになったの", 1, 151, "ユキのプリン", "味も美しい以外の感想が\n出てこないの。ていうかこれを\n食べたミヤコも美しいの！\n鏡、鏡はどこなの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ジー…ってミヤコなにしてるの\nミヤコはストーカーじゃないの！", 3, 53, "知らないうちにお菓子が売れた\n時に思いついたプリンなの。\n作り方もよく覚えてない…\nけど、きっとおいしいの！", 0, 152, "アユミのプリン", "うん、やっぱりおいしく…\nん？あそこにいるのは\nアイツなの。あれ？\n体が勝手にアイツの方に…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("にひひ…イタズラの時間なの！", 3, 54, "イタズラ好きの手下と一緒に\n作ったプリンなの。見た目は\nかわいいけど、作り方は\n意外と複雑なの～", 0, 153, "ミソギのプリン", "見た目通り甘々で優しい味なの\nでも、レシピを見たら裏面に\n別の作り方が書いてあるの。\nこれだと激辛プリンに…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ぴょんぴょこぴょーん、なの♪", 3, 55, "素直でやさしい手下と一緒に\n動物のぬいぐるみをいっぱい\n並べて作ったの", 0, 154, "ミミのプリン", "ん～、ふわふわの甘々なの！\nなんだか楽しくなって\n心も体もるんたったしてくるの", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("へんたいふしんしゃさんなの！", 3, 56, "幽霊を怖がっている手下と\n一緒に作ったプリンなの。\n小さいクセにきっちりしてて\nとってもかわいいプリンなの", 0, 155, "キョウカのプリン", "ひんやりしてて暑い日でも\nおいしく食べられそうなの！\nん？これを買いたい大人が\nいる？それって…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ハート狙い撃ち！なの！", 3, 57, "カリスマモデルなプリンなの\nモリモリにデコレーションして\nカリスマ感を演出したの", 1, 156, "スズナのプリン", "見て食べて楽しめる新機軸の\nプリンなの。ミヤコは幽霊\nだけど自分の足でランウェイを\n歩きたくなってきたの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("授業を始めます♪なの！", 3, 58, "学校の先生をしてるヤツの\nプリンなの。お堅くしようと\nしたら、いつの間にか色っぽく\nなっちゃったの。なんでなの？", 0, 157, "イオのプリン", "プ、プリンは全部ミヤコのもの\nなのに、なんだかこのプリンは\nいろんな人に教えたく\nなっちゃう不思議な味なの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("立派なレディ、なの！", 3, 59, "少し背伸びしたおませな子を\n表現したプリンなの。あえて\n甘さ控えめなの。カラメルは\n後乗せできるから安心するの", 1, 158, "ミサキのプリン", "ミヤコはプリンならどんなもの\nでも食べるの。でもカラメルを\nちょっとだけ足すの。\nちょっとだけなら…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("プリンを持ってこないと\nお仕置きだよ～☆なの！", 3, 60, "謎に包まれたプリンができたの\n何か隠してるようなの…\nこれは危険なプリンなの！", 1, 159, "ホマレのプリン", "味はすごいゴージャスなの！\nボスの風格があるの！\nビッグなミヤコに\nプリンを捧げるの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("たぎってきたの！", 3, 61, "ワイルドな見た目なの！\nこれは期待できそうなの。\nきっと躍動感あふれる味なの！", 1, 160, "カヤのプリン", "最初の一口目が\nすごいインパクトなの！\n無性にケンカしたくなるの！\nプリンをよこせなの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("下剋上、やってやるですなの！", 3, 62, "なんか見た目がパッとしないの\nこれほんとに大丈夫なの？\nなんか頼りないの…", 0, 161, "イノリのプリン", "見た目はアレだけど味はおいし\nいの…あと主張もはっきりして\nるの！やる気と自信だけは\n出てきたのうおおおーなの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("どけどけ～！なの～！", 3, 63, "天下の大悪党のプリンなの\nこれまでのジョーシキに\n捉われないプリンを\n作ってみたの～", 1, 162, "ムイミのプリン", "むむむ…食べたら\nやる気が湧いてきたの！\nミヤコを邪魔するやつはみんな\nまとめてぶっ飛ばしてやるの～", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ミラーミラー！なの！", 3, 64, "いろんなものに変身したり\n分身したりできるヤツの\nプリンなの。型で同じプリンを\nたくさんたくさん作ったの", 1, 163, "ネネカのプリン", "いつのまにか作ったの全部\n食べちゃったの。なんで\nプリンは分身しないの？\n無限に増えろなの！", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("プリンに忠誠を誓いますわ！\nなの！", 3, 65, "金の亡者のプリンなの\n金にものを言わせて作って\nみたの。おばあちゃんの\nプリンと対極なの", 1, 164, "クレジッタのプリン", "むぅ…認めたくないけど\nおいしいの…これを何個も\n作れるほどのお金を稼ぐのは\n大変なの…でもおいしいから…", 5);
INSERT INTO `v1_6152319514a7c787e089d1beeb56f46e1e54fb58996810c2f2542dd38d1f642a` VALUES ("ギルド管理協会へようこそ！\nなの！", 3, 66, "みんなお世話になるギルド\n管理協会職員のプリンなの\nお役所感を出すために手堅く\n王道に作ったの", 1, 165, "カリンのプリン", "手堅い…！手堅いの…！\n隙のないプリンなの！\n今のミヤコなら完璧な\n書類作成ができそうなの！", 5);
